INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 1, 'You''re at your desk during working hours. A team chat message arrives from a colleague asking which colleague was assigned to a particular task last week. You don''t know off the top of your head and would need to check the records. What is the most professional response?', 'multiple_choice', '["Wait until you''ve checked the records and have the full answer, even if that takes 30 minutes.", "Acknowledge the message promptly and confirm when you''ll come back with the full answer.", "Forward the message to someone else without replying to the sender.", "Reply with a guess so the sender doesn''t have to wait."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 2, 'Acknowledging a message promptly with a short holding response is just as professional as providing the full answer straight away.', 'true_false', '["True", "False"]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 3, 'A team member sends a non-urgent message during your working hours. You''re focused on a piece of work that requires deep concentration. The most appropriate response is to:', 'multiple_choice', '["Ignore it until you''ve finished your task --- non-urgent can wait.", "Acknowledge it promptly and signal when you''ll reply fully.", "Stop your work immediately and respond in full.", "Mute notifications until your task is done."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 4, 'You receive an email at 09:00 from a client asking a detailed question. You know the answer but it needs a careful, accurate reply. The best approach is to:', 'multiple_choice', '["Send a quick, simplified reply within minutes just to be seen as responsive.", "Acknowledge promptly that you''ve received it and confirm when you''ll send a full reply.", "Take as long as you need to craft a perfect reply, even if that takes a few hours.", "Forward the question to your manager without telling the client."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 5, 'If a client emails you during your working hours and you''re in a meeting until later that morning, it''s acceptable to wait until the following working day to reply.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 6, 'Which of these is the LEAST acceptable reason for failing to acknowledge a message promptly during working hours?', 'multiple_choice', '["You were in a scheduled meeting.", "You stepped away from your desk for 10 minutes to make a coffee.", "You were on a scheduled call.", "Your laptop had crashed and you were rebooting it."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 7, 'It''s 16:45 and your working day ends at 17:00. A non-urgent message from a colleague arrives. You''d planned to log off promptly today. What''s the most professional approach?', 'multiple_choice', '["Acknowledge briefly now and confirm you''ll reply in detail tomorrow morning.", "Don''t reply --- you can deal with it tomorrow.", "Reply in full now, even if it overruns into your personal time.", "Reply tomorrow without any acknowledgement --- they''ll understand."]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 8, 'Why is fast response time particularly important when working with clients?', 'multiple_choice', '["Because slow responses lead to bad performance reviews.", "Because delays can affect service continuity, trust, and the quality of what you deliver.", "Because regulators directly check response times.", "Because it makes the company look good on social media."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 9, 'Standards for prompt email responses only apply to internal emails --- external emails can wait longer.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 10, 'You receive an email marked URGENT from someone you don''t recognise, claiming to be from an external authority and asking you to send staff personnel files. The email creates significant time pressure. The most professional response is to:', 'multiple_choice', '["Reply quickly with the requested files to be seen as responsive.", "Escalate to your manager and the person responsible for data protection immediately, and don''t send any files until the request is verified.", "Reply quickly asking for verification, but include some general information to be helpful.", "Ignore it entirely --- it''s obviously a phishing attempt."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 11, 'A colleague consistently fails to reply to your messages within working hours, and you have to chase them repeatedly. The most professional way to handle this is to:', 'multiple_choice', '["Stop messaging them and just call instead.", "Raise it directly and politely with them first; escalate to a manager only if it continues.", "Report them to management immediately.", "Match their behaviour and stop replying promptly to theirs."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 12, 'If you genuinely can''t reply fully to a message straight away, simply not replying is preferable to sending a brief acknowledgement.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 13, 'You''ve drafted a four-page document and you''re under time pressure to send it to your manager. The most professional approach is to:', 'multiple_choice', '["Send it immediately and offer to revise after feedback.", "Run a spell-check and then re-read the whole document carefully before sending.", "Run a spell-check only --- it''s faster.", "Ask your manager to proofread it for you before formal submission."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 14, 'You''ve just sent an important email to an external contact and immediately spot a typo in a key term. The most professional response is to:', 'multiple_choice', '["Do nothing --- they''ll understand it''s just a typo.", "Send a brief follow-up with the corrected term.", "Send a long apology email explaining how the error happened.", "Try to recall the email and never acknowledge the error."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 15, 'Spell-check tools catch every error, so re-reading a document after spell-checking is unnecessary.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 16, 'Which of these is the BEST indicator of professional attention to detail in written work?', 'multiple_choice', '["Using complex vocabulary.", "Consistent formatting, accurate spelling, correct grammar, and a clear structure.", "Frequent use of bold and italics for emphasis.", "Writing long sentences to demonstrate thoroughness."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 17, 'You''re given a document template by your manager. You complete it with the required content but change the font and heading colours "to make it look better." Is this professional?', 'multiple_choice', '["Yes --- improving the visual appeal shows initiative.", "No --- templates exist for consistency; you should follow them as given unless asked otherwise.", "Yes, as long as you mention the changes in a covering note.", "No --- but only if your manager notices."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 18, 'Inconsistent formatting within a single document (e.g., mixed fonts, varied indentation, different heading styles) is acceptable as long as the content is accurate.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 19, 'When proofreading your own work, which method tends to be MOST effective at catching errors?', 'multiple_choice', '["Reading it on the same screen immediately after writing it.", "Reading it aloud, or returning to it after a short break, ideally in a different format (e.g., printed or a different view).", "Skim-reading for general flow only.", "Relying entirely on spell-check."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 20, 'You spot that a colleague has sent a document to a client with several spelling errors. The most professional course of action is to:', 'multiple_choice', '["Tell them privately so they can send a corrected version.", "Reply-all pointing out the errors.", "Ignore it --- not your problem.", "Tell their manager directly without speaking to them first."]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 21, 'You consistently struggle to set up your organisation''s approved virtual background quickly before meetings. The most professional response is to:', 'multiple_choice', '["Skip the background for internal meetings --- they''re more informal.", "Set up your environment in advance so the approved background is ready before every meeting starts.", "Always join meetings 5 minutes late to allow setup time.", "Join with the camera off to avoid the issue."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 22, 'A company-approved virtual background is only required when meeting with external clients, not for internal meetings.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 23, 'You''re due to join a meeting with a new client at 11:00. At 10:55, your housemate starts vacuuming loudly in the next room. You should:', 'multiple_choice', '["Join the meeting as planned and hope the noise stops.", "Ask the housemate to pause until the meeting ends and, if they can''t, move to a quieter space before joining.", "Cancel the meeting.", "Mute yourself permanently and use the chat function only."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 24, 'A client has their camera on during a video call. Your background isn''t ideal. The most professional response is to:', 'multiple_choice', '["Keep your camera off --- the background isn''t presentable.", "Turn your camera on with your organisation''s approved virtual background applied.", "Turn your camera on without a background and apologise for the setting.", "Turn the camera on briefly to say hello, then turn it off."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 25, 'It''s acceptable to keep your camera off when the client has theirs on, provided you''ve explained why.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 26, 'You''re in a meeting and a delivery driver knocks loudly at your door, then the dog starts barking. The most professional response is to:', 'multiple_choice', '["Pretend nothing happened and carry on.", "Mute yourself, briefly apologise via chat or when next speaking, handle the disruption, and rejoin promptly.", "Leave the meeting without explanation.", "Explain the disruption at length to the meeting attendees."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 27, 'What is the single most important step before any video meeting?', 'multiple_choice', '["Brushing up on your speaking notes.", "Ensuring your environment, background, audio, and connection are tested and ready.", "Wearing formal clothing.", "Logging in exactly on the start time."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 28, 'Mirroring a client''s choice to have their camera on demonstrates respect and engagement.', 'true_false', '["True", "False"]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 29, 'Halfway through a meeting you realise the virtual background is flickering badly because your lighting has changed. The most professional response is to:', 'multiple_choice', '["Ignore it --- it''s a minor issue.", "Briefly explain you''re addressing a quick technical issue, turn the camera off to fix it, and rejoin once resolved.", "Carry on and apologise repeatedly.", "Leave the meeting entirely."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 30, 'Which of these does NOT contribute to a professional virtual meeting presence?', 'multiple_choice', '["A quiet, distraction-free environment.", "The company-approved virtual background.", "A reasonable webcam and clear audio.", "Eating lunch on camera."]'::jsonb, '[3]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 31, 'Once you''ve completed your initial onboarding training, there''s no need to refresh or update your knowledge afterwards.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 32, 'Your annual training refresh is due in three weeks, but you''re very busy operationally. The most professional response is to:', 'multiple_choice', '["Wait until you''re prompted to complete it.", "Block time in your diary now to ensure it''s completed before the deadline.", "Ask for an extension before attempting it.", "Skip it this year --- you completed it last year."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 33, 'You''re using an industry term in conversations but you realise you don''t fully understand what it means. The most professional response is to:', 'multiple_choice', '["Avoid using the term in future to hide that you don''t understand it.", "Research it properly (e.g., official guidance, the regulator''s website) and ask a colleague to clarify if it''s still unclear.", "Wait until someone explains it to you.", "Carry on using it and hope no one asks for a definition."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 34, 'You''re new to the UK care sector. Which of these BEST demonstrates a professional approach to learning about it?', 'multiple_choice', '["Only learning what''s directly relevant to your immediate tasks.", "Proactively researching the regulator, key terms, relevant laws, and how care is delivered in the UK.", "Relying on what you''ll pick up through day-to-day work.", "Waiting for your manager to send you a complete learning plan."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 35, 'An employee who actively seeks to understand the wider industry --- its terms, regulator, laws and key concepts --- beyond their own role demonstrates strong professional curiosity.', 'true_false', '["True", "False"]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 36, 'When learning about the rules and regulations of an industry you''re new to, the MOST reliable first source is usually:', 'multiple_choice', '["Friends and family who might know something about it.", "Official sources such as the industry regulator''s website and government guidance.", "Anonymous online forums and discussion threads.", "Whatever pops up first in a search engine."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 37, 'Your manager hasn''t given you a specific learning plan in your first few weeks. The most professional approach is to:', 'multiple_choice', '["Wait until training is allocated to you.", "Proactively research key terms, regulations and core concepts in your own time, and ask your manager what they''d recommend you prioritise.", "Focus only on the tasks given to you and learn the rest as you go.", "Rely on colleagues to teach you everything."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 38, 'Knowing only the specific procedures of your own role is sufficient --- broader industry knowledge isn''t really necessary.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 39, 'A colleague uses an industry acronym you don''t recognise during a meeting. You should:', 'multiple_choice', '["Pretend you understood it and look it up later.", "Ask for clarification, either in the meeting or directly afterwards.", "Avoid contributing to the rest of the meeting.", "Assume it doesn''t matter."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 40, 'In your first three months in a new industry, you''ve been making notes on terminology, key regulations, and how the sector operates. A colleague tells you this is "overkill." What does your approach actually demonstrate?', 'multiple_choice', '["Wasting time on things you don''t need to know.", "A professional attitude --- building durable knowledge that makes you more effective.", "Insecurity about your own ability.", "Showing off."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 41, 'Your home broadband has been intermittent for 20 minutes. You have a meeting in 15 minutes. The most professional action is to:', 'multiple_choice', '["Hope it stabilises and join the meeting as planned.", "Notify your manager and the meeting organiser now, and set up a backup (e.g., mobile hotspot, dial-in).", "Wait until the meeting starts and explain if there are issues.", "Cancel the meeting without explanation."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 42, 'If you wake up unwell and unable to work, you should wait until your shift officially starts to notify your manager.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 43, 'You''ve just been told a family member has been taken to hospital and you need to leave urgently. You''re due to start a meeting in 30 minutes. The most professional response is to:', 'multiple_choice', '["Send a brief message to your manager and the meeting organiser explaining the situation, then leave.", "Leave immediately without telling anyone --- they''ll understand later.", "Attend the meeting first, then deal with the emergency.", "Wait until you arrive at the hospital before notifying anyone."]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 44, 'You''ve been asked to complete a task but you''re not sure what''s expected. You''ve already started, but feel uncertain. The most professional approach is to:', 'multiple_choice', '["Continue, finish to the best of your ability, and submit it.", "Pause, ask for clarification with specific questions, and then proceed.", "Ask a junior colleague to help.", "Wait until your manager checks in on you."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 45, 'Telling your manager you have no work to do is a sign of weakness or lack of initiative.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 46, 'You''ve completed all assigned tasks and have two hours left in your shift. The most professional response is to:', 'multiple_choice', '["Browse non-work content until your shift ends.", "Tell your manager and ask for additional work, or use the time for training and professional development.", "Log off early.", "Pretend to look busy."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 47, 'You realise you''ve made a factually incorrect statement in a document you sent to leadership yesterday. The mistake is small but real. The most professional response is to:', 'multiple_choice', '["Hope nobody notices.", "Inform leadership immediately with a corrected version.", "Wait to see if anyone flags it first.", "Quietly correct it in the master copy without telling anyone."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 48, 'Raising concerns early --- even when you''re not 100% sure they''re justified --- is generally better than waiting until you''re certain.', 'true_false', '["True", "False"]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 49, 'Your laptop crashes mid-task and you lose 90 minutes of unsaved work. The most professional first action is to:', 'multiple_choice', '["Try to recreate the work without telling anyone.", "Inform your manager about the issue and the timeline impact, then proceed with recovery.", "Take an early lunch to recover from the frustration.", "Blame the IT system to your manager."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 50, 'Partway through a complex task, you realise you genuinely don''t have the skills to complete it well. The deadline is tomorrow. You should:', 'multiple_choice', '["Submit poor-quality work and hope it''s accepted.", "Inform your manager today, explain the gap, and ask for support or a revised approach.", "Ask a colleague to do it for you secretly.", "Submit what you have and explain afterwards."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 51, 'Asking for clarification on a task is a sign you weren''t paying attention when it was originally assigned.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 52, 'Which of these communication failures is MOST damaging to professional trust?', 'multiple_choice', '["Asking too many clarifying questions.", "Staying silent about challenges until they become serious problems.", "Acknowledging messages before fully responding to them.", "Asking for help when stuck."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 53, 'You''ve been struggling with a task for two days but haven''t told anyone. You''ve now missed the deadline. The most professional thing to say to your manager is:', 'multiple_choice', '["\"Sorry it''s late --- I''ve just had a lot on.\"", "\"I''m sorry --- I should have raised earlier that I was struggling. Here''s where I am and what I think I need to finish it well.\"", "Nothing --- submit it late and hope they don''t ask.", "Blame the brief for being unclear."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 54, 'It''s better to attempt a task badly and submit it on time than to ask for help and submit it later.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 55, 'Which behaviour MOST demonstrates initiative and self-direction?', 'multiple_choice', '["Waiting for instructions before acting.", "Identifying that you have spare capacity, flagging it, and suggesting where you could add value.", "Filling your time with low-value work to look busy.", "Asking permission before every minor action."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 56, 'Giving two weeks'' notice for paid annual leave is always sufficient, regardless of your employer''s policy.', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 57, 'You want to take a week off in three months'' time. When should you submit the leave request?', 'multiple_choice', '["As soon as you know --- typically at least a month in advance.", "Two weeks before the leave starts.", "The day before the leave starts.", "Only after you''ve already booked the holiday."]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 58, 'You''ve already booked a non-refundable holiday for three weeks'' time, but you haven''t yet submitted a formal leave request. You should:', 'multiple_choice', '["Inform your manager immediately, acknowledge the short notice, and submit the request now.", "Wait until closer to the date to avoid drawing attention to it.", "Take the leave without telling anyone formally.", "Cancel the holiday."]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 59, 'Giving early notice of leave shows respect for the team and allows for proper cover planning.', 'true_false', '["True", "False"]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 60, 'Why is early notice (at least a month in advance) for paid leave important to employers?', 'multiple_choice', '["Because it''s a legal requirement.", "Because cover planning takes time, and last-minute requests disrupt the team and any clients you serve.", "Because last-minute requests are always rejected.", "Because the payroll system requires it."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 61, 'You realise at 08:55 that you''ll be 10 minutes late to a 09:00 meeting because the previous one is overrunning. The most professional response is to:', 'multiple_choice', '["Slip in late without comment.", "Send a quick message to the organiser explaining you''ll be 10 minutes late.", "Skip the meeting entirely.", "Make up an excuse on arrival."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 62, 'Being on time is a baseline expectation, not a bonus quality to be praised.', 'true_false', '["True", "False"]'::jsonb, '[0]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 63, 'You''re consistently 5 minutes late to morning meetings because of a school drop-off you can''t change. The most professional approach is to:', 'multiple_choice', '["Continue arriving late --- it''s only 5 minutes.", "Discuss it with your manager openly and either adjust the meeting time or arrange a workaround.", "Skip the morning meetings entirely.", "Pretend technical issues are the cause."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 64, 'Which of these has the biggest impact on professional reputation in a remote-working environment?', 'multiple_choice', '["Being early to meetings.", "Consistent reliability --- being on time, responsive, and communicative.", "Being friendly in chat.", "Working long hours."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 65, 'Punctuality matters less in virtual meetings because joining is "just a click."', 'true_false', '["True", "False"]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 66, 'It''s 09:10 on Monday. You have: (1) a client email expecting a reply by 11:00, (2) a chat message from your manager asking for a status update, (3) a 09:30 meeting with an important external contact, and (4) outstanding annual training due to expire on Wednesday. What''s the most professional order of action?', 'multiple_choice', '["Do the training first because of the deadline.", "Send a one-line acknowledgement to your manager, prepare for and attend the 09:30 meeting, then reply to the client email before 11:00, and schedule the training into your diary for later this week.", "Skip the 09:30 meeting to clear the other tasks.", "Do whichever feels easiest first."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 67, 'A colleague has asked you to cover a meeting with a client tomorrow because they''re unwell. You''ve never met this client and don''t know the background. The meeting is in 18 hours. The most professional approach is to:', 'multiple_choice', '["Decline because you don''t have enough information.", "Accept; review the client file, recent correspondence, and ask the colleague (or another team member) for a short handover note tonight so you can lead competently tomorrow.", "Accept and wing it on the day.", "Forward the meeting on to your manager."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 68, 'Your manager has set a deadline that you genuinely believe is unrealistic given your current workload. The most professional response is to:', 'multiple_choice', '["Accept it and miss the deadline if necessary.", "Raise it openly with your manager, explain your current commitments, and agree on priorities or a revised timeline.", "Decline the task.", "Complain to colleagues without raising it formally."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 69, 'A client sends an angry email accusing your team of getting something seriously wrong. You don''t yet know whether the allegation has merit. The most professional response is to:', 'multiple_choice', '["Apologise and admit fault to defuse the situation.", "Acknowledge receipt promptly, escalate immediately to your manager, and reply substantively only once a proper review has been done.", "Wait until you''ve fully investigated before replying at all.", "Ignore the email and let your manager handle it."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 70, 'You''re working on a confidential document. Your child interrupts you and you need to step away from your laptop for 5 minutes. The most professional response is to:', 'multiple_choice', '["Leave the document open --- you''ll only be 5 minutes.", "Lock your screen before stepping away.", "Close the laptop without saving.", "Ask your child to wait."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 71, 'A colleague forwards you a chat message containing a screenshot of a client''s personal data, asking for your opinion. The most professional response is to:', 'multiple_choice', '["Reply with your opinion quickly so they aren''t kept waiting.", "Don''t engage with the personal data on that channel; flag the data protection concern, ask the colleague to move the discussion to a secure channel, and notify your manager if it looks like a breach.", "Delete the message and forget about it.", "Forward it on to other colleagues for their views."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 72, 'You''ve just joined a video meeting and realise your microphone is picking up the TV from another room. The meeting has already started. The most professional response is to:', 'multiple_choice', '["Carry on and hope no one notices.", "Mute yourself immediately, send a brief chat message that you''re resolving an audio issue, fix it, and rejoin properly.", "Leave the meeting without explanation.", "Apologise verbally at length while the noise continues."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 73, 'You''ve been asked to draft a document on a topic you know nothing about. Your deadline is in five working days. The most professional first step is to:', 'multiple_choice', '["Start writing immediately based on what you can guess.", "Spend the first day researching the topic, relevant guidance, and any existing templates, and clarify the scope with your manager before drafting.", "Decline the task.", "Copy a similar document from another organisation and adapt it lightly."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 74, 'A group chat of colleagues starts discussing a manager''s performance in a way you find unprofessional. The most professional response is to:', 'multiple_choice', '["Join in --- it''s important to fit in with the team.", "Stay out of the conversation; if the behaviour continues or starts affecting work, raise it appropriately through proper channels.", "Take screenshots and report it to HR immediately.", "Leave the group without explanation."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 75, 'You receive conflicting instructions from two managers. Each says their task is the highest priority. The most professional response is to:', 'multiple_choice', '["Pick the one you prefer and do that first.", "Bring them together (or message both) to clarify priorities transparently so you can plan.", "Attempt both at the same time, at half quality.", "Do neither until they sort it out between themselves."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 76, 'You discover that a colleague has been copying and pasting content from another organisation''s documents into your company''s documents without rewriting them. The most professional response is to:', 'multiple_choice', '["Ignore it --- not your problem.", "Raise it privately with the colleague first; if it isn''t addressed, escalate to your manager given the compliance and intellectual property risks.", "Report it directly to leadership without speaking to them first.", "Do the same yourself to save time."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 77, 'You''re scheduled to interview a candidate at 14:00 but at 13:45 you realise you haven''t reviewed their CV. The most professional approach is to:', 'multiple_choice', '["Wing the interview --- your experience will carry you through.", "Use the next 10 minutes to read the CV carefully and prepare 3--4 specific questions, then start the interview on time and prepared.", "Postpone the interview.", "Ask the candidate to summarise their CV at the start of the meeting."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 78, 'A colleague consistently sends you tasks at 16:55 (your shift ends at 17:00) tagged "urgent." The most professional response is to:', 'multiple_choice', '["Stay late and do them --- that''s the job.", "Raise the pattern directly and politely with the colleague, clarify whether they''re genuinely urgent, and agree a better way of working together.", "Ignore the late tasks entirely.", "Match their behaviour and start sending late requests of your own."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 79, 'Mid-meeting, you realise you don''t understand a key term being used. The conversation is moving fast. The most professional response is to:', 'multiple_choice', '["Stay quiet and look it up later.", "Politely interrupt and ask for a brief clarification --- others may benefit too.", "Pretend to understand and write the term down to look up later.", "Leave the meeting."]'::jsonb, '[1]'::jsonb, 1);
INSERT INTO public.recruitment_questions (test_id, position, question_text, question_type, options, correct_answers, weight) VALUES ('ee9a991d-b770-424c-93bf-ed03493e59c6', 80, 'Reflecting on the qualities tested across this assessment, which best summarises the kind of staff member who excels in a remote-working role?', 'multiple_choice', '["Someone who keeps their head down and works hard alone.", "Someone who is responsive, detail-oriented, proactive in communication, punctual, continually learning about their industry, and professional in their virtual presence.", "Someone who never makes mistakes.", "Someone who works the longest hours."]'::jsonb, '[1]'::jsonb, 1);